{
  "$schema": "https://json.schemastore.org/nx-workspace.json",
  "defaultBase": "main",
  "namedInputs": {
    "default": ["{projectRoot}/**/*", "sharedGlobals"],
    "production": [
      "default",
      "!{projectRoot}/**/?(*.)+(spec|test).[jt]s?(x)?(.snap)",
      "!{projectRoot}/tsconfig.spec.json",
      "!{projectRoot}/.eslintrc.json",
      "!{projectRoot}/eslint.config.js",
      "!{projectRoot}/**/*.md"
    ],
    "sharedGlobals": ["{workspaceRoot}/.rust-toolchain", "{workspaceRoot}/.nvmrc"]
  },
  "targetDefaults": {
    "build": {
      "dependsOn": ["^build"],
      "inputs": ["production", "^production"],
      "outputs": [],
      "cache": true,
      "parallel": false
    },
    "test": {
      "dependsOn": ["build"],
      "inputs": ["default", "^production", "{workspaceRoot}/docs/fixtures/**/*"],
      "cache": true,
      "parallel": false
    },
    "lint": {
      "inputs": ["default"],
      "cache": true,
      "parallel": false
    },
    "clippy": {
      "inputs": ["default", "^production"],
      "cache": true,
      "parallel": false
    },
    "complexity": {
      "inputs": ["default", "^production", "{workspaceRoot}/clippy.toml"],
      "cache": true,
      "parallel": false
    },
    "audit": {
      "cache": false
    },
    "outdated": {
      "cache": false
    }
  },
  "plugins": [],
  "pluginsConfig": {
    "@nx/js": {
      "analyzeLockfile": false
    }
  },
  "generators": {},
  "release": {
    "version": {
      "conventionalCommits": true
    },
    "changelog": {
      "workspaceChangelog": false,
      "projectChangelogs": true
    }
  },
  "nxCloudId": "6982782356ddb434b5932321",
  "analytics": true
}

