   197	/// Encode waypoints to raw bitpacked bytes with header and payload.
   198	fn encode_raw_bitpacked(waypoints: &[Waypoint]) -> Result<Vec<u8>, Error> {
   199	    // Validate all system IDs and find max offset
   200	    let mut max_offset = 0u32;
   201	    for wp in waypoints {
   202	        if wp.system_id < BASE_SYSTEM_ID {
   203	            return Err(Error::FmapInvalidSystemId {
   204	                system_id: wp.system_id,
   205	                base_id: BASE_SYSTEM_ID,
   206	            });
   207	        }
   208	        let offset = wp.system_id - BASE_SYSTEM_ID;
   209	        if offset > max_offset {
   210	            max_offset = offset;
   211	        }
   212	    }
   213	
   214	    let k = calculate_bit_width(max_offset);
   215	    if k > MAX_BIT_WIDTH {
   216	        return Err(Error::FmapInvalidBitWidth { k });
   217	    }
   218	
   219	    // Build header
   220	    let count = waypoints.len() as u16;
   221	    let mut header = vec![FMAP_VERSION, k, 0u8, 0u8];
   222	    header[2..4].copy_from_slice(&count.to_be_bytes());
   223	
   224	    // Pack waypoints into bits
   225	    let mut writer = BitWriter::new();
   226	    for wp in waypoints {
   227	        let offset = wp.system_id - BASE_SYSTEM_ID;
   228	        writer.write_bits(offset, k);
   229	        writer.write_bits(wp.waypoint_type as u32, WAYPOINT_TYPE_BITS);
   230	    }
   231	    let payload = writer.finish();
   232	
   233	    Ok([header, payload].concat())
   234	}
