   305	fn get_or_build_index(
   306	    starmap: &Starmap,
   307	    options: &GraphBuildOptions,
   308	) -> (Arc<SpatialIndex>, Option<usize>) {
   309	    if let Some(ref index) = options.spatial_index {
   310	        return (Arc::clone(index), None);
   311	    }
   312	
   313	    // Build spatial index in-memory (may be slow for large datasets)
   314	    let system_count = starmap.systems.len();
   315	    let index = Arc::new(SpatialIndex::build(starmap));
   316	    (index, Some(system_count))
