   324	    let mut adjacency: HashMap<SystemId, Vec<Edge>> = HashMap::new();
   325	
   326	    for system in starmap.systems.values() {
   327	        let Some(position) = system.position else {
   328	            adjacency.entry(system.id).or_default();
