   336	        // radius query which returns only systems within that distance. This avoids
   337	        // fetching the whole dataset when a physical per-hop limit is known.
   338	        let neighbors: Vec<(SystemId, f64)> = if let Some(radius) = options.max_jump {
   339	            index.within_radius_filtered(query_point, radius, options.max_temperature)
   340	        } else if max_neighbors == 0 {
   341	            // Unlimited neighbours requested but no radius provided. For small datasets
   342	            // we can safely fetch all neighbours; for very large datasets this becomes
   343	            // O(n^2) and can take an exceptionally long time. Cap the fetch to a
   344	            // reasonable upper bound and emit a warning so callers can tune behaviour
   345	            // with `--max-spatial-neighbours` or `--max-jump`.
   346	            let system_count = starmap.systems.len();
