   349	                    systems = system_count,
   350	                    cap = MAX_SAFE_NEIGHBOURS,
   351	                    "unlimited spatial neighbours requested on large dataset; capping neighbours per-node for performance; consider using --max-spatial-neighbours or --max-jump"
   352	                );
   353	                let k = MAX_SAFE_NEIGHBOURS + 1; // +1 to account for self
   354	                let query = NeighbourQuery {
   355	                    k,
   356	                    radius: None,
   357	                    max_temperature: options.max_temperature,
   358	                };
