   389	                target,
   390	                kind: EdgeKind::Spatial,
   391	                distance,
   392	            })
   393	            .collect()
   394	        } else if max_neighbors == 0 {
   395	            // Unlimited: use whatever the radius query returned
   396	            iter.map(|(target, distance)| Edge {
   397	                target,
   398	                kind: EdgeKind::Spatial,
   399	                distance,
   400	            })
