   931	fn extract_archive(archive_path: &Path, destination: &Path) -> Result<()> {
   932	    let parent = destination
   933	        .parent()
   934	        .ok_or(Error::CacheDirsUnavailable)?
   935	        .to_path_buf();
   936	    fs::create_dir_all(&parent)?;
   937	
   938	    let file = File::open(archive_path)?;
   939	    let mut archive = ZipArchive::new(file)?;
   940	
   941	    for idx in 0..archive.len() {
   942	        let mut entry = archive.by_index(idx)?;
   943	        if !entry.is_file() {
   944	            continue;
   945	        }
   946	
   947	        // Explicit validation: skip entries with path traversal attempts
   948	        let safe_name = match entry.enclosed_name() {
   949	            Some(path) => path.to_string_lossy().to_ascii_lowercase(),
   950	            None => {
   951	                // enclosed_name() returns None for unsafe paths like "../../../etc/passwd"
   952	                warn!(
   953	                    "skipping archive entry with unsafe path in {}",
   954	                    archive_path.display()
   955	                );
   956	                continue;
   957	            }
   958	        };
   959	
   960	        if safe_name.ends_with(".db") {
   961	            let mut tmp = NamedTempFile::new_in(&parent)?;
   962	            io::copy(&mut entry, tmp.as_file_mut())?;
   963	            tmp.flush()?;
   964	            if destination.exists() {
   965	                fs::remove_file(destination)?;
   966	            }
   967	            tmp.persist(destination).map_err(|err| err.error)?;
   968	            return Ok(());
   969	        }
   970	    }
   971	
   972	    Err(Error::ArchiveMissingDatabase {
   973	        archive: archive_path.to_path_buf(),
   974	    })
   975	}
