   977	fn copy_cached_to_target(cached: &Path, target: &Path) -> Result<()> {
   978	    if cached == target {
   979	        return Ok(());
   980	    }
   981	
   982	    if let Some(parent) = target.parent() {
   983	        fs::create_dir_all(parent)?;
   984	        copy_file_atomic(cached, target)
   985	    } else {
   986	        warn!(target = %target.display(), "dataset target path lacks parent directory");
   987	        copy_file_atomic(cached, target)
