   149	    /// This error indicates that during decoding, adding the BASE_SYSTEM_ID to an offset value
   150	    /// caused integer overflow. This suggests either malformed fmap data or an offset that is
   151	    /// unreasonably large.
   152	    #[error("system ID offset {system_id} caused overflow when adding base ID {base_id}")]
   153	    FmapInvalidSystemId { system_id: u32, base_id: u32 },
   154	}
   155	
   156	fn format_suggestions(suggestions: &[String]) -> String {
   157	    if suggestions.is_empty() {
   158	        String::new()
   159	    } else if suggestions.len() == 1 {
   160	        format!(". Did you mean '{}'?", suggestions[0])
   161	    } else {
   162	        format!(
   163	            ". Did you mean one of: {}?",
   164	            suggestions
   165	                .iter()
   166	                .map(|s| format!("'{}'", s))
   167	                .collect::<Vec<_>>()
   168	                .join(", ")
   169	        )
   170	    }
